# Let me now create a campaign classification based on patterns I see:
# 1. I$NDA (with $) - likely a special campaign
# 2. CAN vs Canada - might be different campaigns
# 3. US vs United States - might be different campaigns
# 4. UK vs United Kingdom - might be different campaigns

# Let me create a campaign field based on these patterns
def identify_campaign(row):
    country = row['country']

    # Special campaign markers
    if '$' in country:
        return 'Special_Campaign_' + country.replace('$', 'S')

    # Different country code formats might represent different campaigns
    if country == 'US':
        return 'Campaign_US_Short'
    elif country == 'United States':
        return 'Campaign_US_Full'
    elif country == 'UK':
        return 'Campaign_UK_Short'
    elif country == 'United Kingdom':
        return 'Campaign_UK_Full'
    elif country == 'CAN':
        return 'Campaign_CAN_Short'
    elif country == 'Canada':
        return 'Campaign_Canada_Full'
    elif country == 'India':
        return 'Campaign_India'
    elif country == 'Australia':
        return 'Campaign_Australia'
    elif country == 'Germany':
        return 'Campaign_Germany'
    elif country == 'France':
        return 'Campaign_France'
    elif country == 'Brazil':
        return 'Campaign_Brazil'
    else:
        return 'Campaign_Other'

